import{_ as e,o as t,c as r,ag as o}from"./chunks/framework.C9sp7nFj.js";const u=JSON.parse('{"title":"欧洲铁路通票","description":"Eurail欧洲铁路通票购买和使用攻略","frontmatter":{"title":"欧洲铁路通票","description":"Eurail欧洲铁路通票购买和使用攻略"},"headers":[],"relativePath":"knowledge/transportation/eurail.md","filePath":"knowledge/transportation/eurail.md","lastUpdated":null}'),i={name:"knowledge/transportation/eurail.md"};function l(n,a,d,s,h,c){return t(),r("div",null,[...a[0]||(a[0]=[o('<h1 id="欧洲铁路通票" tabindex="-1">欧洲铁路通票 <a class="header-anchor" href="#欧洲铁路通票" aria-label="Permalink to &quot;欧洲铁路通票&quot;">​</a></h1><h2 id="通票类型" tabindex="-1">通票类型 <a class="header-anchor" href="#通票类型" aria-label="Permalink to &quot;通票类型&quot;">​</a></h2><p>Eurail通票分为全球通票和单国通票。全球通票覆盖33个国家，单国通票适合深度游览一国。</p><h2 id="价格对比" tabindex="-1">价格对比 <a class="header-anchor" href="#价格对比" aria-label="Permalink to &quot;价格对比&quot;">​</a></h2><p>通票价格根据旅行天数和乘坐等级（一等/二等）而定。连续通票适合密集行程，灵活通票适合悠闲旅行。</p><h2 id="使用技巧" tabindex="-1">使用技巧 <a class="header-anchor" href="#使用技巧" aria-label="Permalink to &quot;使用技巧&quot;">​</a></h2><p>高速列车需要提前预订座位并额外付费。夜间列车可以节省住宿费用。</p><h2 id="预订座位" tabindex="-1">预订座位 <a class="header-anchor" href="#预订座位" aria-label="Permalink to &quot;预订座位&quot;">​</a></h2><p>部分列车强制要求预订座位。建议提前在欧洲铁路官网或火车站预订，旺季时热门班次可能售罄。</p>',9)])])}const _=e(i,[["render",l]]);export{u as __pageData,_ as default};
